export type PieceColor = 'w' | 'b';
export type PieceType = 'p' | 'n' | 'b' | 'r' | 'q' | 'k';
export type SquareColor = 'light' | 'dark';

export interface Piece {
  type: PieceType;
  color: PieceColor;
}

export interface Square {
  row: number;
  col: number;
  color: SquareColor;
  piece: Piece | null;
}

export interface Move {
  from: string;
  to: string;
  piece: Piece;
  captured?: Piece;
  promotion?: PieceType;
  san: string;
}

export type GameStatus = 'ongoing' | 'check' | 'checkmate' | 'stalemate' | 'draw';

export interface GameState {
  board: Map<string, Piece | null>;
  turn: PieceColor;
  selectedSquare: string | null;
  validMoves: string[];
  moveHistory: Move[];
  capturedPieces: {
    white: Piece[];
    black: Piece[];
  };
  gameStatus: GameStatus;
  lastMove?: {
    from: string;
    to: string;
  };
}

export interface ChessGameHookReturn {
  // State
  board: Map<string, Piece | null>;
  turn: PieceColor;
  selectedSquare: string | null;
  validMoves: string[];
  moveHistory: Move[];
  capturedPieces: {
    white: Piece[];
    black: Piece[];
  };
  gameStatus: GameStatus;
  lastMove?: {
    from: string;
    to: string;
  };

  // Actions
  selectSquare: (square: string) => void;
  makeMove: (from: string, to: string, promotion?: PieceType) => boolean;
  undoMove: () => void;
  resetGame: () => void;
  flipBoard: () => void;

  // Helpers
  getPieceAt: (square: string) => Piece | null;
  isSquareInCheck: (square: string) => boolean;
  isGameOver: () => boolean;
}

