import { useState, useCallback, useEffect } from 'react';
import { Chess, SQUARES, type Square } from 'chess.js';
import type { Piece, PieceColor, PieceType, Move, GameStatus, ChessGameHookReturn } from '../types/chess.types';

const fenToPiece = (fen: string | undefined | null): Piece | null => {
  if (!fen || fen === '-') return null;

  const color: PieceColor = fen === fen.toUpperCase() ? 'w' : 'b';
  const type = fen.toLowerCase() as PieceType;

  return { type, color };
};

const getPieceUnicode = (piece: Piece): string => {
  const symbols: Record<PieceColor, Record<PieceType, string>> = {
    w: { k: '♔', q: '♕', r: '♖', b: '♗', n: '♘', p: '♙' },
    b: { k: '♚', q: '♛', r: '♜', b: '♝', n: '♞', p: '♟' }
  };
  return symbols[piece.color][piece.type];
};

export const useChessGame = (): ChessGameHookReturn => {
  const [game] = useState(() => new Chess());
  const [board, setBoard] = useState<Map<string, Piece | null>>(new Map());
  const [turn, setTurn] = useState<PieceColor>('w');
  const [selectedSquare, setSelectedSquare] = useState<string | null>(null);
  const [validMoves, setValidMoves] = useState<string[]>([]);
  const [moveHistory, setMoveHistory] = useState<Move[]>([]);
  const [capturedPieces, setCapturedPieces] = useState<{
    white: Piece[];
    black: Piece[];
  }>({ white: [], black: [] });
  const [gameStatus, setGameStatus] = useState<GameStatus>('ongoing');
  const [lastMove, setLastMove] = useState<{ from: string; to: string } | undefined>();

  const updateBoardState = useCallback(() => {
    const newBoard = new Map<string, Piece | null>();

    Object.keys(SQUARES).forEach(square => {
      const piece = game.get(square as Square);
      newBoard.set(square, fenToPiece(piece));
    });

    setBoard(newBoard);
    setTurn(game.turn() as PieceColor);
    setGameStatus(determineGameStatus());
  }, [game]);

  const determineGameStatus = (): GameStatus => {
    if (game.isCheckmate()) return 'checkmate';
    if (game.isStalemate()) return 'stalemate';
    if (game.isDraw()) return 'draw';
    if (game.isCheck()) return 'check';
    return 'ongoing';
  };

  const selectSquare = useCallback((square: string) => {
    const piece = board.get(square);

    if (selectedSquare && validMoves.includes(square)) {
      makeMove(selectedSquare, square);
      return;
    }

    if (piece && piece.color === turn) {
      setSelectedSquare(square);
      const moves = game.moves({ square: square as Square, verbose: true });
      setValidMoves(moves.map(m => m.to));
    } else {
      setSelectedSquare(null);
      setValidMoves([]);
    }
  }, [selectedSquare, board, turn, validMoves, game, makeMove]);

  const makeMove = useCallback((from: string, to: string, promotion?: PieceType): boolean => {
    try {
      const move = game.move({
        from,
        to,
        promotion: promotion || 'q'
      });

      if (!move) return false;

      const newMove: Move = {
        from: move.from,
        to: move.to,
        piece: fenToPiece(move.piece)!,
        captured: move.captured ? fenToPiece(move.captured) || undefined : undefined,
        promotion: move.promotion,
        san: move.san
      };

      setMoveHistory(prev => [...prev, newMove]);
      setLastMove({ from, to });

      if (move.captured) {
        const capturedPiece = fenToPiece(move.captured)!;
        setCapturedPieces(prev => {
          const color = capturedPiece.color === 'w' ? 'white' : 'black';
          return {
            ...prev,
            [color]: [...prev[color], capturedPiece]
          };
        });
      }

      setSelectedSquare(null);
      setValidMoves([]);
      updateBoardState();

      return true;
    } catch (e) {
      return false;
    }
  }, [game, updateBoardState]);

  const undoMove = useCallback(() => {
    const move = game.undo();
    if (move) {
      setMoveHistory(prev => prev.slice(0, -1));

      if (move.captured) {
        const capturedPiece = fenToPiece(move.captured)!;
        setCapturedPieces(prev => {
          const color = capturedPiece.color === 'w' ? 'white' : 'black';
          return {
            ...prev,
            [color]: prev[color].slice(0, -1)
          };
        });
      }

      const lastMoveIndex = moveHistory.length - 2;
      if (lastMoveIndex >= 0) {
        const lastMoveRecord = moveHistory[lastMoveIndex];
        setLastMove({ from: lastMoveRecord.from, to: lastMoveRecord.to });
      } else {
        setLastMove(undefined);
      }

      setSelectedSquare(null);
      setValidMoves([]);
      updateBoardState();
    }
  }, [game, moveHistory, updateBoardState]);

  const resetGame = useCallback(() => {
    game.reset();
    setMoveHistory([]);
    setCapturedPieces({ white: [], black: [] });
    setSelectedSquare(null);
    setValidMoves([]);
    setLastMove(undefined);
    updateBoardState();
  }, [game, updateBoardState]);

  const getPieceAt = useCallback((square: string): Piece | null => {
    return board.get(square) || null;
  }, [board]);

  const isSquareInCheck = useCallback((square: string): boolean => {
    const piece = board.get(square);
    return piece?.type === 'k' && piece.color === turn && game.isCheck();
  }, [board, turn, game]);

  const isGameOver = useCallback((): boolean => {
    return game.isGameOver();
  }, [game]);

  useEffect(() => {
    updateBoardState();
  }, [updateBoardState]);

  return {
    board,
    turn,
    selectedSquare,
    validMoves,
    moveHistory,
    capturedPieces,
    gameStatus,
    lastMove,
    selectSquare,
    makeMove,
    undoMove,
    resetGame,
    flipBoard: () => {}, // Visual flip handled by ChessBoard component
    getPieceAt,
    isSquareInCheck,
    isGameOver
  };
};

